package co.edu.elecciones.controller; import co.edu.elecciones.commons.dto.ApiResponse; import co.edu.elecciones.domain.*; import co.edu.elecciones.dto.Requests; import co.edu.elecciones.repository.*; import co.edu.elecciones.service.AuditService; import jakarta.servlet.http.HttpServletRequest; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/elecciones") public class EleccionesController { private final ElectionRepository repo; private final AuditService audit;  public EleccionesController(ElectionRepository repo, AuditService audit){this.repo=repo;this.audit=audit;}
 @GetMapping public ApiResponse<List<Election>> all(){return ApiResponse.ok("OK",repo.findAll());}
 @GetMapping("/{id}") public ApiResponse<Election> one(@PathVariable Long id){return ApiResponse.ok("OK",repo.findById(id).orElseThrow());}
 @PostMapping public ApiResponse<Election> create(@RequestBody Requests.ElectionRequest req, HttpServletRequest http){ Election u=new Election(); u.name=req.name(); u.type=req.type(); u.round=req.round(); u.electionDate=req.electionDate(); u.state=req.state(); var saved=repo.save(u); audit.log("CREATE","Election",saved.id,"Creación",http); return ApiResponse.ok("Creado",saved);}
 @PutMapping("/{id}") public ApiResponse<Election> update(@PathVariable Long id,@RequestBody Requests.ElectionRequest req,HttpServletRequest http){ var u=repo.findById(id).orElseThrow(); u.name=req.name(); u.type=req.type(); u.round=req.round(); u.electionDate=req.electionDate(); u.state=req.state(); var saved=repo.save(u); audit.log("UPDATE","Election",saved.id,"Actualización",http); return ApiResponse.ok("Actualizado",saved);}
 @DeleteMapping("/{id}") public ApiResponse<Void> delete(@PathVariable Long id,HttpServletRequest http){repo.deleteById(id); audit.log("DELETE","Election",id,"Eliminación",http); return ApiResponse.ok("Eliminado",null);}
}
